import subprocess, json, threading, pathlib, os, time

class LspClient:
    """Minimal LSP client over subprocess stdin/stdout."""

    def __init__(self, cmd: list[str], workspace_root: str):
        self._proc = subprocess.Popen(cmd, stdin=subprocess.PIPE,
                                      stdout=subprocess.PIPE, stderr=subprocess.DEVNULL)
        self._id = 0
        self._pending: dict = {}
        self._lock = threading.Lock()
        self._workspace_root = workspace_root
        threading.Thread(target=self._read_loop, daemon=True).start()

    def _send(self, msg: dict) -> None:
        body = json.dumps(msg).encode()
        self._proc.stdin.write(f"Content-Length: {len(body)}\r\n\r\n".encode() + body)
        self._proc.stdin.flush()

    def _read_loop(self) -> None:
        while True:
            raw = b""
            while not raw.endswith(b"\r\n\r\n"):
                c = self._proc.stdout.read(1)
                if not c: return
                raw += c
            length = int(next(h for h in raw.decode().splitlines()
                              if "Content-Length" in h).split(":")[1])
            msg = json.loads(self._proc.stdout.read(length))
            if "id" in msg:
                with self._lock:
                    self._pending[msg["id"]] = msg

    def request(self, method: str, params: dict) -> dict:
        self._id += 1; rid = self._id
        with self._lock: self._pending[rid] = None
        self._send({"jsonrpc": "2.0", "id": rid, "method": method, "params": params})
        deadline = time.time() + 30
        while time.time() < deadline:
            with self._lock:
                r = self._pending.get(rid)
            if r is not None:
                with self._lock: del self._pending[rid]
                return r
            time.sleep(0.01)
        raise TimeoutError(method)

    def notify(self, method: str, params: dict) -> None:
        self._send({"jsonrpc": "2.0", "method": method, "params": params})

    def initialize(self) -> None:
        self.request("initialize", {
            "processId": os.getpid(),
            "rootUri": pathlib.Path(self._workspace_root).as_uri(),
            "capabilities": {"textDocument": {"definition": {}, "references": {}, "hover": {}}},
            "workspaceFolders": None,
        })
        self.notify("initialized", {})

    def open_file(self, fpath: str) -> None:
        self.notify("textDocument/didOpen", {"textDocument": {
            "uri": pathlib.Path(fpath).as_uri(), "languageId": "typescript",
            "version": 1, "text": pathlib.Path(fpath).read_text("utf-8"),
        }})

    def definition(self, fpath: str, line: int, character: int) -> list:
        resp = self.request("textDocument/definition", {
            "textDocument": {"uri": pathlib.Path(fpath).as_uri()},
            "position": {"line": line, "character": character},
        })
        result = resp.get("result") or []
        return result if isinstance(result, list) else [result]

    def shutdown(self) -> None:
        self.request("shutdown", {}); self.notify("exit", {})
        self._proc.wait(timeout=5)


# --- Usage ---
workspace = "/path/to/myproject"
client = LspClient(["typescript-language-server", "--stdio"], workspace)
client.initialize()
client.open_file(f"{workspace}/src/app.ts")
locations = client.definition(f"{workspace}/src/app.ts", line=10, character=5)
for loc in locations:
    s = loc["range"]["start"]
    print(f"{loc['uri']}:{s['line']+1}:{s['character']+1}")
client.shutdown()

import pathlib
from dataclasses import dataclass

@dataclass
class Location:
    uri: str
    line: int
    character: int

def find_definition(client: LspClient, workspace: str, symbol: str) -> Location | None:
    """Locate canonical definition of `symbol` using LSP go-to-definition."""
    for fpath in pathlib.Path(workspace).rglob("*.ts"):
        if "node_modules" in str(fpath):
            continue
        for lineno, line_text in enumerate(fpath.read_text("utf-8").splitlines()):
            col = line_text.find(symbol)
            if col == -1:
                continue
            client.open_file(str(fpath))
            defs = client.definition(str(fpath), lineno, col)
            if defs:
                d = defs[0]["range"]["start"]
                return Location(uri=defs[0]["uri"], line=d["line"], character=d["character"])
    return None

def collect_references(client: LspClient, defn: Location) -> list[dict]:
    """Return every workspace reference to the symbol at `defn`."""
    client.open_file(defn.uri.removeprefix("file://"))
    resp = client.request("textDocument/references", {
        "textDocument": {"uri": defn.uri},
        "position":     {"line": defn.line, "character": defn.character},
        "context":      {"includeDeclaration": True},
    })
    return resp.get("result") or []


# --- Find all callers of "processOrder" ---
workspace = "/path/to/myproject"
client = LspClient(["typescript-language-server", "--stdio"], workspace)
client.initialize()

defn = find_definition(client, workspace, "processOrder")
if defn:
    refs = collect_references(client, defn)
    for ref in refs:
        s = ref["range"]["start"]
        print(f"{ref['uri']}:{s['line']+1}:{s['character']+1}")
client.shutdown()
